def test_dispute_at_exactly_60_days_boundary(api_client, create_transaction):
    txn = create_transaction(age_days=60)
    payload = {"transaction_id": txn["id"], "reason": "unauthorized_charge"}

    resp = api_client.post("/disputes", json=payload)
    body = resp.json()

    assert resp.status_code in (201, 422), (
        f"Unexpected status {resp.status_code} at 60-day boundary"
    )
    if resp.status_code == 201:
        assert "dispute_id" in body
        assert body["provisional_credit"] is True
    else:
        assert "error" in body
